import{_ as e,c as a,o,a as i}from"./app.ae51eafc.js";const _=JSON.parse('{"title":"Introducci\xF3n","description":"","frontmatter":{},"headers":[],"relativePath":"start/intro.md"}'),r={name:"start/intro.md"},s=i('<h1 id="introduccion" tabindex="-1">Introducci\xF3n <a class="header-anchor" href="#introduccion" aria-hidden="true">#</a></h1><p>El aprendizaje del marco t\xE9cnico Scrum es el primer paso aconsejable para familiarizarse con la Gesti\xF3n \xC1gil. Inicialmente se recomienda adoptarlo aplicando reglas definidas adoptando los Pilares, los Roles, los Artefactos y los Eventos originales.</p><p>Una vez iniciados en Scrum, y con el conocimiento que el propio equipo acumula a trav\xE9s de las retrospectivas, se pueden ir <em>\u201Crompiendo\u201D</em> las reglas y adoptar la parte pragm\xE1tica, personalizada y m\xE1s adecuada a las propias circunstancias del propio equipo y proyecto.</p><blockquote><p>Seg\xFAn <a href="https://en.wikipedia.org/wiki/Jeff_Sutherland" target="_blank" rel="noreferrer">Jeff Sutherland</a>, uno de los creadores de Scrum y del m\xE9todo de control emp\xEDrico de procesos en el cual se basa dicha metodolog\xEDa, \xE9ste se sostiene en la implementaci\xF3n de tres pilares: <strong>transparencia</strong> (visibilidad de los procesos), <strong>inspecci\xF3n</strong> (peri\xF3dica del proceso) y <strong>adaptaci\xF3n</strong> (de los procesos inspeccionado).</p></blockquote><p>La transparencia, la inspecci\xF3n y la adaptaci\xF3n son conceptos estrechamente relacionados, cuya finalidad es permitir que un equipo pueda mejorar y entregar productos de valor en el momento indicado. Scrum brinda las herramientas y los momentos adecuados para que estos tres pilares puedan verse reflejados a lo largo de todo el proceso.</p><p>Esta parte del temario ense\xF1a la parte t\xE9cnica, basado en la aplicaci\xF3n de reglas concretas en un marco de <strong>roles</strong>, <strong>artefactos</strong> y <strong>eventos</strong> definidos.</p><p><strong>Marco T\xE9cnico</strong></p><ul><li><strong>Roles</strong><ul><li>El Due\xF1o del Producto</li><li>El Equipo de Desarrollo</li><li>El L\xEDder de Desarrollo</li><li>El Gestor del Proyecto</li><li>El Equipo de Pruebas</li><li>El Administrador Base de Datos</li><li>El Director de Inform\xE1tica</li></ul></li><li><strong>Artefactos</strong><ul><li>Historia de Usuario</li><li>Historias T\xE9cnicas</li><li>Pila del Producto</li><li>Pila del Sprint</li><li>Incremento</li></ul></li><li><strong>Eventos</strong><ul><li>Reuni\xF3n de Planificaci\xF3n del Sprint</li><li>Reuni\xF3n de Apertura Diaria</li><li>Sprint</li><li>Revisi\xF3n del Sprint</li><li>Retrospectiva del Sprint</li></ul></li></ul>',8),l=[s];function n(t,c,d,p,u,m){return o(),a("div",null,l)}const f=e(r,[["render",n]]);export{_ as __pageData,f as default};
